class ShoppingCart {
  private subtotal: number = 0;
  private currency: string = 'USD';

  addItem(price: number, currency: string): void {
    if (currency !== this.currency) {
      throw new Error(`Expected ${this.currency}, got ${currency}`);
    }
    this.subtotal += price;
  }

  getTotal(): number {
    return this.subtotal;
  }
}

